USE gold_saleslt;
GO

CREATE SCHEMA salesDW;
GO

CREATE OR ALTER VIEW salesDW.dim_customer AS
SELECT * FROM OPENROWSET(
    BULK   'https://storageproject12026.dfs.core.windows.net/gold/saleslt/dim_customer',
    FORMAT = 'DELTA'
) AS r;
GO

